import{c as t,Q as o,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"Reason Why 90% of AI Workflows Die in 30 Days (And the 3 Rules That Keep Them Alive)","description":"","frontmatter":{"title":"Reason Why 90% of AI Workflows Die in 30 Days (And the 3 Rules That Keep Them Alive)","date":"2026-05-17T00:00:00.000Z","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-17-@sairahul1-531815.md","filePath":"research/tweets/2026-05-17-@sairahul1-531815.md","lastUpdated":1779894392000}'),n={name:"research/tweets/2026-05-17-@sairahul1-531815.md"};function s(i,e,h,l,u,d){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="reason-why-90-of-ai-workflows-die-in-30-days-and-the-3-rules-that-keep-them-alive" tabindex="-1">Reason Why 90% of AI Workflows Die in 30 Days (And the 3 Rules That Keep Them Alive) <a class="header-anchor" href="#reason-why-90-of-ai-workflows-die-in-30-days-and-the-3-rules-that-keep-them-alive" aria-label="Permalink to &quot;Reason Why 90% of AI Workflows Die in 30 Days (And the 3 Rules That Keep Them Alive)&quot;">​</a></h1><p><strong>來源</strong>: <a href="https://x.com/sairahul1" target="_blank" rel="noreferrer">@sairahul1</a> · <a href="https://x.com/sairahul1/status/2055935584158531815" target="_blank" rel="noreferrer">原始推文</a><br><strong>日期</strong>: 2026-05-17<br><strong>統計</strong>: 👍 78 · 🔁 9 · 🔖 452 · 👁 302,751<br><strong>評分</strong>: 7.15/10 · <strong>整合決策</strong>: Rule</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>AI 工作流 30 天內夭折三大原因：沒有 job description、無聲失敗未偵測、跑在筆電上而非真正 infrastructure；三個規則全補上才能存活超過 30 天。</p><hr><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><ol><li><strong>Rule 1 — No job description, no agent</strong>：Agent 設計不是寫 prompt，是寫 job description（五要素：watches / reads / produces / doesn&#39;t do / success condition）；用「vibe」（「幫我處理客服信件」）建的 agent 必死</li><li><strong>Rule 2 — Silent failure 才是殺手</strong>：Loud failure 有 error 可修；Silent failure 外觀正常卻輸出垃圾，直到客戶截圖才發現；解法三層：canary output（可秒驗的欄位）+ silent failure alert（空輸出改發警報）+ 每週 spot check（4 分鐘）</li><li><strong>Rule 3 — 筆電不是 infrastructure</strong>：關蓋即死；三個替代方案：VPS + PM2（$12/月，自動重啟）、managed agent platform、serverless + scheduler（Lambda + EventBridge）</li></ol><hr><h2 id="關鍵數據-工具-引用" tabindex="-1">關鍵數據 / 工具 / 引用 <a class="header-anchor" href="#關鍵數據-工具-引用" aria-label="Permalink to &quot;關鍵數據 / 工具 / 引用&quot;">​</a></h2><ul><li><strong>Job description 五要素</strong>：What it watches / What it reads / What it produces / What it doesn&#39;t do / How you know it worked</li><li><strong>Canary output 範例</strong>：<code>Sources checked: 8. Items processed: N. Most recent item timestamp: [ts]</code> — N=0 或 timestamp &gt; 8 天 → 發 alert 不發 brief</li><li><strong>Infrastructure 三選一</strong>：VPS + PM2/Supervisor（$12/月）· managed agent platform · AWS Lambda/GCP Cloud Functions + EventBridge/Cloud Scheduler</li><li><strong>作者個人案例</strong>：競品監控 workflow 跑 6 個月，只漏 2 個 cycle，兩次都發了 alert 說明原因；週 spot check 6 個月內抓到 2 次 drift</li></ul><hr><h2 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h2><ol><li><strong>「90%」無數據支撐</strong>：核心主張是作者觀察，非研究引用；說服力完全依賴 narrative；可信但不可驗</li><li><strong>Rule 1 五要素對初學者仍抽象</strong>：「exact sources」「exact output format」說得正確但未提供模板；缺少填空範本</li><li><strong>Infrastructure 建議偏技術</strong>：VPS + PM2 對非工程師門檻不低；managed platform 未給具名平台（Inngest? Modal? Temporal?）</li></ol><hr><h2 id="_5-維度評分" tabindex="-1">5 維度評分 <a class="header-anchor" href="#_5-維度評分" aria-label="Permalink to &quot;5 維度評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>9</td><td>三規則 + 五要素 + canary output 設計可直接套用下一個 agent 建構</td></tr><tr><td>B. 創新性 (20%)</td><td>6</td><td>Silent failure / canary output 有一定原創性；job description 框架和 infra 要求屬常識</td></tr><tr><td>C. 證據品質 (20%)</td><td>5</td><td>「90%」無引用；個人案例是唯一 evidence；narrative 強但數據弱</td></tr><tr><td>D. 技術深度 (15%)</td><td>7</td><td>PM2/Supervisor/Lambda/EventBridge 具名；canary output 設計具體</td></tr><tr><td>E. 泛化性 (15%)</td><td>8</td><td>適用所有 AI agent/workflow，不限技術棧或領域</td></tr></tbody></table><p><strong>加權總分</strong>: 9×0.3 + 6×0.2 + 5×0.2 + 7×0.15 + 8×0.15 = <strong>7.15/10</strong></p><hr><h2 id="整合決策" tabindex="-1">整合決策 <a class="header-anchor" href="#整合決策" aria-label="Permalink to &quot;整合決策&quot;">​</a></h2><p><strong>Rule</strong> — 總分 &gt; 6，三個規則是通用 Agent 設計原則（job description 框架、silent failure 防護、infrastructure 要求），適合整合進 Agent 建構 checklist 或 CLAUDE.md workflow 規範</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Your AI workflow is running right now.</p><p>You just do not know it stopped working three days ago.</p><p>It is still firing. Still burning API credits. Still sending outputs nobody is reading. The agent you spent two weekends building is producing garbage at $0.40 per garbage pile — and you will not find out until a customer screenshots it and sends it to you on a Tuesday.</p><p>This is not bad luck. This is the default outcome.</p><p>Save this. You will read it twice.</p><h2 id="the-30-day-graveyard" tabindex="-1">The 30-Day Graveyard <a class="header-anchor" href="#the-30-day-graveyard" aria-label="Permalink to &quot;The 30-Day Graveyard&quot;">​</a></h2><p>Every week, hundreds of founders build AI workflows and post them on Twitter.</p><p>The demo looks clean. The thread gets likes. The replies say &quot;this is the future.&quot;</p><p>Thirty days later, the workflow is dead.</p><p>Not deleted. Not replaced. Dead and still running. Charging the card. Producing nothing useful. The founder moved on. The agent did not get the memo.</p><p>90% of AI workflows built today will not survive their first month in production. Not because the models are bad. Not because the ideas are wrong. Because the builders made three mistakes that guarantee failure — and nobody told them what those mistakes were before they shipped.</p><p>This is that article.</p><h2 id="why-they-die" tabindex="-1">Why They Die <a class="header-anchor" href="#why-they-die" aria-label="Permalink to &quot;Why They Die&quot;">​</a></h2><p>Here is the anatomy of a workflow death. It is always the same sequence.</p><p>Day 1: You build it. It works perfectly in the demo. You feel like you unlocked something.</p><p>Day 3: It still works. You stop checking it as carefully.</p><p>Day 9: Something changes. An API response format shifts slightly. A source it was reading goes behind a login wall. The model interprets an edge case differently than it did on day one. The output quietly degrades. Nobody notices.</p><p>Day 14: The workflow is now producing output that is technically a response but substantively useless. It is still running. You are still paying for it.</p><p>Day 23: A customer or a colleague mentions something is off. You investigate. You find 12 days of broken output you thought was being handled.</p><p>Day 30: You kill it. You tell yourself AI is not ready. You move on.</p><p>The model did not fail you. The build failed the model.</p><h2 id="the-3-rules-that-separate-the-10-from-everyone-else" tabindex="-1">The 3 Rules That Separate the 10% From Everyone Else <a class="header-anchor" href="#the-3-rules-that-separate-the-10-from-everyone-else" aria-label="Permalink to &quot;The 3 Rules That Separate the 10% From Everyone Else&quot;">​</a></h2><p>The founders whose workflows survive 30 days, 90 days, a year — they are not smarter. They do not have better prompts. They build with three rules everyone else ignores.</p><p>Rule 1 — No Job Description, No Agent</p><p>Most people build agents with a vibe.</p><p>&quot;Help me with content.&quot; &quot;Monitor competitors.&quot; &quot;Handle customer emails.&quot;</p><p>That is not a job description. That is a wish. And wishes do not survive the weekend.</p><p>A job description has five parts:</p><p>What it watches. The specific trigger or schedule. &quot;Every Monday at 7am&quot; or &quot;every time a new GitHub issue is opened with the label &#39;bug&#39;&quot; or &quot;every time an email arrives from a domain not in my contacts list.&quot; Not &quot;sometimes&quot; or &quot;when relevant.&quot;</p><p>What it reads. The exact sources. Not &quot;check the internet.&quot; &quot;Pull from these three RSS feeds, this Airtable base, and the last 7 days of this Slack channel.&quot; Specific. Bounded. No ambiguity.</p><p>What it produces. The exact output format. Not &quot;a summary.&quot; &quot;A three-section brief: headline finding in one sentence, three supporting bullets with one source each, one recommended action. Under 300 words. In this Google Doc.&quot;</p><p>What it does not do. The guardrails. &quot;Never send an external email without human approval.&quot; &quot;Never modify the production database.&quot; &quot;Never post directly. Always save to drafts.&quot; The things you assume are obvious are the things that will burn you.</p><p>How you know it worked. The success condition. &quot;If the brief is empty, send me a Slack message saying no relevant updates found. Do not send an empty brief.&quot;</p><p>Vibes do not survive the weekend. Job descriptions do.</p><p>Every workflow you build from today forward starts with a job description. Not a prompt. A job description.</p><p>Rule 2 — Silent Failure Is the Only Failure That Kills You</p><p>Loud failures are fine. Loud failures send an error. They stop the workflow. They wake you up. You fix them.</p><p>Silent failures are the ones that kill businesses.</p><p>A silent failure looks like success. The workflow runs. The output arrives. The format is correct. The content is wrong — slightly, then more, then completely — and because it looks right, nobody checks it.</p><p>Here is how silent failure happens in practice:</p><p>Your content agent writes 30 posts. You set it up to auto-schedule the ones that score above 80 on your internal rubric. The rubric was calibrated on your first 20 posts. On day 15, the model starts interpreting your rubric differently. Posts that score 82 are now mediocre by your real standard. They go out anyway. Your engagement drops. You blame the algorithm.</p><p>Your research agent sends a weekly brief. On day 11, one of the sources it was reading changes its URL structure. The agent fails to fetch it silently. It fills the gap with older cached data and does not flag the gap. You read a brief based on stale information and make a decision on it.</p><p>Your inbox triage agent drafts replies. On day 8, it starts categorizing a certain type of email as low priority because the sender&#39;s name matches a pattern in its training. You miss three important emails from a new customer who happens to share a surname with a newsletter you never read.</p><p>In every case: the workflow ran. No error was thrown. You lost anyway.</p><p>The fix is mandatory output verification. Every agent needs three things:</p><p>A canary output. One field in every output that is easy to verify and hard to fake. A timestamp of the most recent source it read. A count of items it processed. A confidence score. Something you can glance at in two seconds and know the agent actually did the work.</p><p>A silent failure alert. If the agent produces nothing, or produces something below a threshold, it does not send an empty output. It sends you an alert. &quot;No results found this cycle — here is what I checked and why I may have found nothing.&quot; Nothing is always more useful than a convincing empty result.</p><p>A weekly spot check. Pick one output per week per agent. Read it fully. Compare it against what you would have written yourself. This takes four minutes. It catches drift before drift becomes failure.</p><p>Agents do not fail loudly. Build for the quiet breaks.</p><p>Rule 3 — Your Laptop Is Not Infrastructure</p><p>This is where 90% of builders die.</p><p>They build locally. The demo works. They ship the Twitter thread. Someone asks if it is running in production. They say yes. What they mean is: it is running on their MacBook, which is currently open, on their desk, in their apartment, connected to their home WiFi, and will stop working when they close the lid to go to the airport on Thursday.</p><p>Your laptop is not infrastructure. It is a development environment that happens to be running something important right now.</p><p>Here is what happens to laptop-hosted agents:</p><p>MacOS pushes an update at 4am. The machine restarts. The agent stops. Nobody knows until Monday.</p><p>You close the lid on a flight. Six hours of workflows missed. The inbox triage agent did not triage. The bug hunter did not hunt. The standup agent sent nothing.</p><p>Your home WiFi drops for twenty minutes. The agent retries. Fails. Moves on. Logs nothing. The window it was supposed to catch is gone.</p><p>You go on vacation. The laptop stays home. Everything stays home with it.</p><p>Real infrastructure runs when you are not watching. It runs when you are asleep, on a plane, at dinner, unreachable for a weekend. It does not need you to keep the lid open.</p><p>The rule is simple: if the workflow needs to run more than once and you cannot afford for it to miss a cycle, it does not live on your laptop.</p><p>The three infrastructure options that actually work:</p><p>A VPS with a process manager. A $12/month server running PM2 or Supervisor. Your agent runs as a managed process. If it crashes, PM2 restarts it automatically. If the server reboots, PM2 starts it on boot. Cheap. Reliable. Not glamorous. Works.</p><p>A managed agent platform. Purpose-built for this. Handles the restarts, the monitoring, the alerting. Costs more than a VPS. Saves you the weekends you would spend debugging why the process died. Worth it once your agents are generating real value.</p><p>Serverless with a scheduler. AWS Lambda or Google Cloud Functions triggered by EventBridge or Cloud Scheduler. Zero infrastructure to manage. You pay per execution. Scales to zero when not running. Best option for agents that run on a fixed schedule rather than continuously.</p><p>None of these are complicated. All of them require fifteen minutes of setup. Every one of them will save you from the 4am macOS update that kills your agents and your Monday morning.</p><p>Close the laptop. The agents should keep running.</p><h2 id="the-workflow-that-survives" tabindex="-1">The Workflow That Survives <a class="header-anchor" href="#the-workflow-that-survives" aria-label="Permalink to &quot;The Workflow That Survives&quot;">​</a></h2><p>Here is what a 90-day workflow looks like when all three rules are applied.</p><p>The job description: Every Monday at 7am, read the last 7 days of posts from these 5 competitor accounts and these 3 industry newsletters. Extract any product announcements, pricing changes, or content that performed above 500 engagements. Compare against last week&#39;s brief. Flag anything new. Output a three-section brief: what changed, what is gaining traction, what gap they left open. If no changes found, send alert: &quot;quiet week — here is what was checked.&quot; Deliver to this Notion page and send a Slack notification.</p><p>The canary output: Every brief includes: &quot;Sources checked: 8. Items processed: [N]. Most recent item timestamp: [timestamp].&quot; If N is zero or the timestamp is more than 8 days old, it sends an alert instead of a brief.</p><p>The infrastructure: Running on a $12/month VPS. PM2 manages the process. If it crashes, it restarts in 30 seconds. A weekly log review takes 3 minutes every Friday.</p><p>The spot check: Every Friday, one brief gets read fully. Takes 4 minutes. Has caught drift twice in six months.</p><p>That workflow has been running for six months. It has missed two cycles — both times it sent an alert explaining why. It has never silently failed.</p><p>That is the difference between a workflow that survives and one that dies on day nine.</p><h2 id="the-uncomfortable-truth" tabindex="-1">The Uncomfortable Truth <a class="header-anchor" href="#the-uncomfortable-truth" aria-label="Permalink to &quot;The Uncomfortable Truth&quot;">​</a></h2><p>Most people will read this, nod, and build their next agent the same way they built the last one.</p><p>A prompt. A demo. A Twitter thread. Thirty days of silence. A dead workflow nobody officially killed.</p><p>The three rules are not complicated. A job description takes twenty minutes to write. Output verification takes one field and one conditional. Infrastructure takes fifteen minutes to set up.</p><p>The gap is not knowledge. The gap is whether you do it before you ship or after the workflow fails.</p><p>Every agent you build without a job description is an agent you will rebuild. Every agent without output verification is an agent that will fail silently. Every agent on your laptop is an agent that will die the next time you close the lid.</p><p>Build them right once. They run forever.</p><h2 id="tl-dr-1" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr-1" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>90% of AI workflows die in 30 days. Always the same three reasons.</p><p>Rule 1 — No job description, no agent. Vibes don&#39;t survive the weekend. Define what it watches, reads, produces, avoids, and how you know it worked. Before you write a single prompt.</p><p>Rule 2 — Silent failure is the only failure that kills you. Loud failures are fine. Silent failures look like success until a customer finds them. Build a canary output, a silent failure alert, and a weekly spot check into every agent.</p><p>Rule 3 — Your laptop is not infrastructure. It runs when the lid is open. Real agents run when you are asleep, on a plane, unreachable for a weekend. VPS, managed platform, or serverless. Pick one. Set it up before you ship.</p><p>The agents that survive are not smarter. They are built right.</p>',110)])])}const f=t(n,[["render",s]]);export{c as __pageData,f as default};
